    const nomesCorretos = dados
        .filter(item => item.json.STATUS === true)
        .map(item => item.json.NOME)
        .filter(nome => typeof nome === 'string' && nome.trim().length > 0);

    const nomesIncorretos = dados
        .filter(item => item.json.STATUS === false)
        .map(item => item.json.NOME)
        .filter(nome => typeof nome === 'string' && nome.trim().length > 0);

    // Adiciona os nomes corretos na mensagem
    if (nomesCorretos.length > 0) {
        mensagem += `${nomesCorretos.join("\n")}\n\n`;
    } else {
        mensagem += "Nenhum nome foi localizado na base de dados.\n\n";
    }

    // Adiciona os nomes incorretos na mensagem, formatando com o texto "Abençoados Não Localizados"
    if (nomesIncorretos.length > 0) {
        mensagem += `*Abençoados Não Localizados:*\n${nomesIncorretos.join("\n")}`;
    }
} else {
    mensagem += "Nenhum dado foi encontrado para o dia de hoje.";
}

// Retorna a mensagem formatada
return [
    {
        json: {
            textMessage: mensagem
        }
    }
];

